import sys

def solve(data: str) -> str:
    leaves = list(map(int, data.split()))
    def search(index: int, depth: int, maximizing: bool, alpha: int, beta: int) -> int:
        if depth == 3:
            return leaves[index]
        if maximizing:
            value = -10**18
            for child in range(2):
                value = max(value, search(index * 2 + child, depth + 1, False, alpha, beta))
                alpha = max(alpha, value)
                if alpha >= beta:
                    break
            return value
        value = 10**18
        for child in range(2):
            value = min(value, search(index * 2 + child, depth + 1, True, alpha, beta))
            beta = min(beta, value)
            if alpha >= beta:
                break
        return value
    return str(search(0, 0, True, -10**18, 10**18))

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
